import React, { useState, useEffect } from 'react';
import { User, Order, MenuItem, OrderItem } from '../types';
import { MENU_ITEMS, Icons, OPERATIONAL_HOURS } from '../constants';
import { Button } from '../components/Button';
import { mockStore } from '../services/mockStore';

interface UserDashboardProps {
  user: User;
  onLogout: () => void;
  onSelectOrder: (order: Order) => void;
}

export const UserDashboard: React.FC<UserDashboardProps> = ({ user, onLogout, onSelectOrder }) => {
  const [activeTab, setActiveTab] = useState<'MENU' | 'HISTORY'>('MENU');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [viewingOrder, setViewingOrder] = useState<Order | null>(null);

  const now = new Date();
  const currentHour = now.getHours();
  const isShopOpen = currentHour >= OPERATIONAL_HOURS.start && currentHour < OPERATIONAL_HOURS.end;

  useEffect(() => {
    setOrders(mockStore.getOrders().filter(o => o.userId === user.id));
  }, [user.id, activeTab]);

  const activeOrders = orders.filter(o => o.status !== 'DELIVERED' && o.status !== 'CANCELLED');
  const pastOrders = orders.filter(o => o.status === 'DELIVERED' || o.status === 'CANCELLED');

  const addToCart = (item: MenuItem) => {
    if (!isShopOpen) return;
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { id: item.id, name: item.name, price: item.price, quantity: 1 }];
    });
  };

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const placeOrder = (paymentMode: 'UPI' | 'COD') => {
    const newOrder: Order = {
      id: 'ORD-' + Math.random().toString(36).substr(2, 6).toUpperCase(),
      userId: user.id,
      userEmail: user.email,
      items: cart,
      totalAmount: total,
      paymentMode,
      status: 'PENDING',
      createdAt: new Date().toISOString(),
      etaMinutes: 15
    };
    mockStore.saveOrder(newOrder);
    setCart([]);
    setOrders(prev => [newOrder, ...prev]);
    onSelectOrder(newOrder);
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-32">
      {/* Header */}
      <header className="bg-white px-6 pt-12 pb-6 border-b sticky top-0 z-20">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h2 className="text-2xl font-black italic text-red-600">FLASH MAN</h2>
            <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">Local Node #001</p>
          </div>
          <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-600"><Icons.User /></button>
        </div>

        {!isShopOpen && (
          <div className="bg-black text-white p-3 rounded-lg flex items-center gap-3 mb-4 text-sm animate-pulse">
            <div className="w-2 h-2 bg-red-600 rounded-full"></div>
            <p className="font-bold">KITCHEN CLOSED: BACK AT 09:00</p>
          </div>
        )}

        {isShopOpen && activeOrders.length > 0 && (
          <div className="bg-red-600 text-white p-4 rounded-xl shadow-lg shadow-red-200 mb-2">
            <div className="flex justify-between items-center">
              <div>
                <p className="text-[10px] font-bold opacity-80 uppercase tracking-widest">Active Order</p>
                <p className="text-lg font-black">{activeOrders[0].status.replace(/_/g, ' ')}</p>
              </div>
              <Button variant="secondary" onClick={() => onSelectOrder(activeOrders[0])} className="py-2 px-4 text-xs">TRACK</Button>
            </div>
          </div>
        )}
      </header>

      {/* Main Content */}
      <main className="p-6">
        {activeTab === 'MENU' ? (
          <div className="space-y-6">
            <h3 className="text-xl font-black uppercase tracking-tight">Today's Fast Menu</h3>
            <div className="grid gap-4">
              {MENU_ITEMS.map(item => (
                <div key={item.id} className="bg-white rounded-2xl overflow-hidden shadow-sm flex border border-gray-100">
                  <img src={item.image} alt={item.name} className="w-24 h-24 object-cover" />
                  <div className="p-4 flex-1 flex flex-col">
                    <div className="flex justify-between items-start">
                      <h4 className="font-bold text-gray-900">{item.name}</h4>
                      <p className="font-black text-red-600">₹{item.price}</p>
                    </div>
                    <p className="text-xs text-gray-500 line-clamp-2 mt-1 mb-2">{item.description}</p>
                    <button 
                      disabled={!isShopOpen}
                      onClick={() => addToCart(item)}
                      className="mt-auto self-end bg-black text-white px-4 py-1.5 rounded-full text-xs font-bold hover:bg-red-600 transition-colors disabled:opacity-30"
                    >
                      + ADD
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <h3 className="text-xl font-black uppercase tracking-tight">Order History</h3>
            {pastOrders.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
                <p className="text-gray-400 font-medium">No past orders yet.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {pastOrders.map(order => (
                  <div key={order.id} className="bg-white p-4 rounded-xl border border-gray-100">
                    <div className="flex justify-between mb-2">
                      <p className="text-xs font-bold text-gray-400">{order.id}</p>
                      <p className="text-xs font-black text-red-600">{new Date(order.createdAt).toLocaleDateString()}</p>
                    </div>
                    <p className="text-sm font-bold text-gray-800">{order.items.map(i => `${i.quantity}x ${i.name}`).join(', ')}</p>
                    <div className="flex justify-between items-center mt-3">
                      <p className="font-black">₹{order.totalAmount}</p>
                      <Button variant="outline" className="py-1 px-4 text-xs" onClick={() => {
                        setCart(order.items);
                        setActiveTab('MENU');
                      }}>REORDER</Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>

      {/* Cart Sheet / Floating Tab */}
      {cart.length > 0 && (
        <div className="fixed bottom-24 left-6 right-6 bg-black text-white p-6 rounded-2xl shadow-2xl z-30 animate-fade-in">
          <div className="flex justify-between items-center mb-4">
            <h4 className="font-black italic text-xl">FLASH CART</h4>
            <button onClick={() => setCart([])} className="text-xs font-bold opacity-60">CLEAR</button>
          </div>
          <div className="space-y-2 mb-4 max-h-32 overflow-y-auto">
            {cart.map(item => (
              <div key={item.id} className="flex justify-between text-sm">
                <span>{item.quantity}x {item.name}</span>
                <span className="font-bold">₹{item.price * item.quantity}</span>
              </div>
            ))}
          </div>
          <div className="border-t border-white/20 pt-4 mb-4 flex justify-between">
            <span className="font-bold uppercase tracking-widest text-xs">Total Amount</span>
            <span className="font-black text-lg">₹{total}</span>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <Button className="bg-white text-black py-2.5" onClick={() => placeOrder('UPI')}>PAY UPI</Button>
            <Button variant="primary" className="py-2.5" onClick={() => placeOrder('COD')}>COD</Button>
          </div>
        </div>
      )}

      {/* Bottom Nav */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t flex justify-around p-4 z-40">
        <button 
          onClick={() => setActiveTab('MENU')}
          className={`flex flex-col items-center gap-1 ${activeTab === 'MENU' ? 'text-red-600' : 'text-gray-400'}`}
        >
          <div className="p-2"><Icons.Flash /></div>
          <span className="text-[10px] font-bold uppercase tracking-widest">Menu</span>
        </button>
        <button 
          onClick={() => setActiveTab('HISTORY')}
          className={`flex flex-col items-center gap-1 ${activeTab === 'HISTORY' ? 'text-red-600' : 'text-gray-400'}`}
        >
          <div className="p-2"><Icons.History /></div>
          <span className="text-[10px] font-bold uppercase tracking-widest">History</span>
        </button>
      </nav>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { Order, OrderStatus } from '../types';
import { Icons } from '../constants';
import { Button } from '../components/Button';
import { mockStore } from '../services/mockStore';

export const TrackingView: React.FC<{ order: Order, onBack: () => void }> = ({ order, onBack }) => {
  const [currentOrder, setCurrentOrder] = useState<Order>(order);

  // Simulate order progression for demo
  useEffect(() => {
    const interval = setInterval(() => {
      const orders = mockStore.getOrders();
      const freshOrder = orders.find(o => o.id === order.id);
      if (freshOrder) setCurrentOrder(freshOrder);
    }, 2000);
    return () => clearInterval(interval);
  }, [order.id]);

  const steps: { status: OrderStatus; label: string; desc: string }[] = [
    { status: 'PENDING', label: 'Ordered', desc: 'Kitchen received your request' },
    { status: 'PREPARING', label: 'Preparing', desc: 'Chefs are working their magic' },
    { status: 'OUT_FOR_DELIVERY', label: 'On the Way', desc: 'Flash Rider is zooming to you' },
    { status: 'DELIVERED', label: 'Delivered', desc: 'Enjoy your fresh meal!' }
  ];

  const currentIdx = steps.findIndex(s => s.status === currentOrder.status);

  return (
    <div className="min-h-screen bg-white flex flex-col p-6">
      <header className="flex items-center gap-4 mb-8">
        <button onClick={onBack} className="p-2 -ml-2 text-gray-400"><Icons.History /></button>
        <div>
          <h2 className="text-xl font-black italic">TRACK ORDER</h2>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{currentOrder.id}</p>
        </div>
      </header>

      <div className="bg-red-600 text-white rounded-3xl p-8 mb-12 shadow-2xl shadow-red-200 relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-xs font-bold uppercase tracking-[0.2em] opacity-80 mb-1">Estimated Arrival</p>
          <div className="flex items-baseline gap-2">
            <h3 className="text-6xl font-black italic">12</h3>
            <span className="text-xl font-bold uppercase italic">MINS</span>
          </div>
        </div>
        <div className="absolute right-[-20px] bottom-[-20px] opacity-10">
          <Icons.Flash />
        </div>
      </div>

      <div className="space-y-10 pl-4 relative">
        <div className="absolute left-4 top-2 bottom-2 w-0.5 bg-gray-100"></div>
        {steps.map((step, idx) => {
          const isDone = idx < currentIdx;
          const isCurrent = idx === currentIdx;
          const isPending = idx > currentIdx;

          return (
            <div key={step.status} className="flex gap-6 relative">
              <div className={`w-3 h-3 rounded-full z-10 mt-1.5 ring-4 ${
                isDone ? 'bg-red-600 ring-red-100' : 
                isCurrent ? 'bg-red-600 animate-pulse ring-red-100' : 
                'bg-gray-200 ring-transparent'
              }`} />
              <div>
                <h4 className={`font-black uppercase tracking-tight ${isPending ? 'text-gray-300' : 'text-gray-900'}`}>
                  {step.label}
                </h4>
                <p className={`text-xs font-medium ${isPending ? 'text-gray-200' : 'text-gray-500'}`}>
                  {step.desc}
                </p>
              </div>
            </div>
          );
        })}
      </div>

      <div className="mt-auto pt-8 flex flex-col items-center">
        <div className="bg-gray-50 w-full p-4 rounded-2xl border border-gray-100 flex items-center gap-4 mb-6">
          <div className="w-12 h-12 bg-black rounded-full flex items-center justify-center text-white">
            <Icons.User />
          </div>
          <div>
            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Your Flash Rider</p>
            <p className="font-black uppercase">Deepak R.</p>
          </div>
          <button className="ml-auto bg-red-600 p-3 rounded-xl text-white">
            <Icons.Flash />
          </button>
        </div>
        <Button variant="outline" fullWidth onClick={onBack}>BACK TO DASHBOARD</Button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, User } from '../types';
import { mockStore } from '../services/mockStore';
import { Icons, OPERATIONAL_HOURS } from '../constants';
import { Button } from '../components/Button';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

export const AdminDashboard: React.FC<{ user: User, onLogout: () => void }> = ({ user, onLogout }) => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'LIVE' | 'ANALYTICS' | 'SETTINGS'>('LIVE');
  const [kitchenStatus, setKitchenStatus] = useState(true);

  const fetchOrders = () => {
    setOrders(mockStore.getOrders().sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()));
  };

  useEffect(() => {
    fetchOrders();
    const interval = setInterval(fetchOrders, 3000);
