import React, { useState, useEffect } from 'react';
import { ViewState, User, Order } from './types';
import { SplashView } from './views/SplashView';
import { AuthView } from './views/AuthView';
import { UserDashboard } from './views/UserDashboard';
import { AdminDashboard } from './views/AdminDashboard';
import { TrackingView } from './views/TrackingView';
import { mockStore } from './services/mockStore';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('SPLASH');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeOrder, setActiveOrder] = useState<Order | null>(null);

  useEffect(() => {
    // Check for existing session
    const user = mockStore.getUser();
    if (user) {
      setCurrentUser(user);
    }
  }, []);

  const handleSplashFinish = () => {
    if (currentUser) {
      setView(currentUser.role === 'ADMIN' ? 'ADMIN' : 'DASHBOARD');
    } else {
      setView('AUTH');
    }
  };

  const handleAuth = (user: User) => {
    setCurrentUser(user);
    setView(user.role === 'ADMIN' ? 'ADMIN' : 'DASHBOARD');
  };

  const handleLogout = () => {
    mockStore.setUser(null);
    setCurrentUser(null);
    setView('AUTH');
  };

  const renderView = () => {
    switch (view) {
      case 'SPLASH':
        return <SplashView onFinish={handleSplashFinish} />;
      case 'AUTH':
        return <AuthView onAuth={handleAuth} />;
      case 'DASHBOARD':
        return currentUser ? (
          <UserDashboard 
            user={currentUser} 
            onLogout={handleLogout} 
            onSelectOrder={(order) => {
              setActiveOrder(order);
              setView('TRACKING');
            }} 
          />
        ) : <AuthView onAuth={handleAuth} />;
      case 'ADMIN':
        return currentUser?.role === 'ADMIN' ? (
          <AdminDashboard user={currentUser} onLogout={handleLogout} />
        ) : <AuthView onAuth={handleAuth} />;
      case 'TRACKING':
        return activeOrder ? (
          <TrackingView order={activeOrder} onBack={() => setView('DASHBOARD')} />
        ) : <UserDashboard user={currentUser!} onLogout={handleLogout} onSelectOrder={() => {}} />;
      default:
        return <SplashView onFinish={handleSplashFinish} />;
    }
  };

  return (
    <div className="antialiased selection:bg-red-100 selection:text-red-600 min-h-screen">
      {renderView()}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, Order, MenuItem, OrderItem } from '../types';
import { MENU_ITEMS, Icons, OPERATIONAL_HOURS } from '../constants';
import { Button } from '../components/Button';
