import React, { useState, useEffect } from 'react';
import { User, Order, MenuItem, OrderItem } from '../types.ts';
import { MENU_ITEMS, Icons, OPERATIONAL_HOURS } from '../constants.tsx';
import { Button } from '../components/Button.tsx';
import { mockStore } from '../services/mockStore.ts';

interface UserDashboardProps {
  user: User;
  onLogout: () => void;
  onSelectOrder: (order: Order) => void;
}

export const UserDashboard: React.FC<UserDashboardProps> = ({ user, onLogout, onSelectOrder }) => {
  const [activeTab, setActiveTab] = useState<'MENU' | 'HISTORY'>('MENU');
  const [cart, setCart] = useState<OrderItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);

  const now = new Date();
  const currentHour = now.getHours();
  const isShopOpen = currentHour >= OPERATIONAL_HOURS.start && currentHour < OPERATIONAL_HOURS.end;

  useEffect(() => {
    setOrders(mockStore.getOrders().filter(o => o.userId === user.id));
  }, [user.id, activeTab]);

  const activeOrders = orders.filter(o => o.status !== 'DELIVERED' && o.status !== 'CANCELLED');
  const pastOrders = orders.filter(o => o.status === 'DELIVERED' || o.status === 'CANCELLED');

  const addToCart = (item: MenuItem) => {
    if (!isShopOpen) return;
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { id: item.id, name: item.name, price: item.price, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const placeOrder = (paymentMode: 'UPI' | 'COD') => {
    if (cart.length === 0) return;
    const newOrder: Order = {
      id: 'ORD-' + Math.random().toString(36).substr(2, 6).toUpperCase(),
      userId: user.id,
      userEmail: user.email,
      items: cart,
      totalAmount: total,
      paymentMode,
      status: 'PENDING',
      createdAt: new Date().toISOString(),
      etaMinutes: 15
    };
    mockStore.saveOrder(newOrder);
    setCart([]);
    setOrders(prev => [newOrder, ...prev]);
    onSelectOrder(newOrder);
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-40">
      <header className="bg-white px-6 pt-12 pb-6 border-b sticky top-0 z-20">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h2 className="text-2xl font-black italic text-red-600">FLASH MAN</h2>
            <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">Local Node #001</p>
          </div>
          <button onClick={onLogout} className="p-2 text-gray-400 hover:text-red-600">
            <Icons.User />
          </button>
        </div>

        {!isShopOpen && (
          <div className="bg-black text-white p-3 rounded-lg flex items-center gap-3 mb-4 text-sm animate-pulse">
            <div className="w-2 h-2 bg-red-600 rounded-full"></div>
            <p className="font-bold">KITCHEN CLOSED: BACK AT 09:00</p>
          </div>
        )}

        {isShopOpen && activeOrders.length > 0 && (
          <div className="bg-red-600 text-white p-4 rounded-xl shadow-lg shadow-red-200 mb-2">
            <div className="flex justify-between items-center">
              <div>
                <p className="text-[10px] font-bold opacity-80 uppercase tracking-widest">Active Order</p>
                <p className="text-lg font-black">{activeOrders[0]?.status.replace(/_/g, ' ') || 'PROCESSING'}</p>
              </div>
              <Button variant="secondary" onClick={() => onSelectOrder(activeOrders[0])} className="py-2 px-4 text-xs">TRACK</Button>
            </div>
          </div>
        )}
      </header>

      <main className="p-6">
        {activeTab === 'MENU' ? (
          <div className="space-y-6">
            <h3 className="text-xl font-black uppercase tracking-tight">Today's Fast Menu</h3>
            <div className="grid gap-4">
              {MENU_ITEMS.map(item => (
                <div key={item.id} className="bg-white rounded-2xl overflow-hidden shadow-sm flex border border-gray-100">
                  <img src={item.image} alt={item.name} className="w-24 h-24 object-cover" />
                  <div className="p-4 flex-1 flex flex-col">
                    <div className="flex justify-between items-start">
                      <h4 className="font-bold text-gray-900">{item.name}</h4>
                      <p className="font-black text-red-600">₹{item.price}</p>
                    </div>
                    <p className="text-xs text-gray-500 line-clamp-2 mt-1 mb-2">{item.description}</p>
                    <button 
                      disabled={!isShopOpen}
                      onClick={() => addToCart(item)}
                      className="mt-auto self-end bg-black text-white px-4 py-1.5 rounded-full text-xs font-bold hover:bg-red-600 transition-colors disabled:opacity-30"
                    >
                      + ADD
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <h3 className="text-xl font-black uppercase tracking-tight">Order History</h3>
            {pastOrders.length === 0 ? (
              <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
                <p className="text-gray-400 font-medium">No past orders yet.</p>
              </div>
            ) : (
              <div className="space-y-4">
                {pastOrders.map(order => (
                  <div key={order.id} className="bg-white p-4 rounded-xl border border-gray-100">
                    <div className="flex justify-between mb-2">
                      <p className="text-xs font-bold text-gray-400">{order.id}</p>
                      <p className="text-xs font-black text-red-600">{new Date(order.createdAt).toLocaleDateString()}</p>
                    </div>
                    <p className="text-sm font-bold text-gray-800">{order.items.map(i => `${i.quantity}x ${i.name}`).join(', ')}</p>
                    <div className="flex justify-between items-center mt-3">
                      <p className="font-black">₹{order.totalAmount}</p>
                      <Button variant="outline" className="py-1 px-4 text-xs" onClick={() => {
                        setCart(order.items);
                        setActiveTab('MENU');
                      }}>REORDER</Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>

      {cart.length > 0 && (
        <div className="fixed bottom-24 left-6 right-6 bg-black text-white p-6 rounded-2xl shadow-2xl z-30 animate-fade-in border border-white/10">
          <div className="flex justify-between items-center mb-6">
            <div>
              <h4 className="font-black italic text-xl">FLASH CART</h4>
              <p className="text-[10px] font-bold opacity-50 uppercase tracking-widest">{cart.length} {cart.length === 1 ? 'item' : 'items'}</p>
            </div>
            <button onClick={() => setCart([])} className="text-xs font-bold opacity-60 hover:opacity-100 transition-opacity">CLEAR ALL</button>
          </div>

          <div className="space-y-3 mb-6 max-h-48 overflow-y-auto">
            {cart.map(item => (
              <div key={item.id} className="flex items-center justify-between bg-white/5 p-3 rounded-xl gap-4">
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-bold truncate">{item.name}</p>
                  <p className="text-[10px] opacity-40 uppercase font-black">₹{item.price} UNIT</p>
                </div>

                <div className="flex items-center bg-white/10 rounded-full px-2 py-1 gap-4">
                  <button 
                    onClick={() => updateQuantity(item.id, -1)} 
                    className="text-lg font-bold w-5 h-5 flex items-center justify-center hover:text-red-500 transition-colors"
                  >-</button>
                  <span className="text-xs font-black w-4 text-center">{item.quantity}</span>
                  <button 
                    onClick={() => updateQuantity(item.id, 1)} 
                    className="text-lg font-bold w-5 h-5 flex items-center justify-center hover:text-green-500 transition-colors"
                  >+</button>
                </div>

                <div className="text-right min-w-[60px]">
                  <p className="text-sm font-black text-red-500">₹{item.price * item.quantity}</p>
                </div>

                <button 
                  onClick={() => removeFromCart(item.id)} 
                  className="text-white/20 hover:text-red-600 transition-colors p-1"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </div>
            ))}
          </div>

          <div className="border-t border-white/10 pt-4 mb-6 flex justify-between items-center">
            <span className="font-bold uppercase tracking-[0.2em] text-xs opacity-50">Grand Total</span>
            <span className="font-black text-2xl text-white italic">₹{total}</span>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <Button className="bg-white text-black py-3 rounded-xl hover:bg-gray-100" onClick={() => placeOrder('UPI')}>PAY UPI</Button>
            <Button variant="primary" className="py-3 rounded-xl" onClick={() => placeOrder('COD')}>COD</Button>
          </div>
        </div>
      )}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t flex justify-around p-4 z-40">
        <button 
          onClick={() => setActiveTab('MENU')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'MENU' ? 'text-red-600' : 'text-gray-400 hover:text-gray-600'}`}
        >
          <div className="p-2"><Icons.Flash /></div>
          <span className="text-[10px] font-bold uppercase tracking-widest">Menu</span>
        </button>
        <button 
          onClick={() => setActiveTab('HISTORY')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'HISTORY' ? 'text-red-600' : 'text-gray-400 hover:text-gray-600'}`}
        >
          <div className="p-2"><Icons.History /></div>
          <span className="text-[10px] font-bold uppercase tracking-widest">History</span>
        </button>
      </nav>
    </div>
  );
};

