            required
            className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-red-600 focus:bg-white rounded-xl outline-none transition-all"
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
